    # ── Calculate marks-based field scores (0–100 per field) ──────────────────
    # Only marks >= MARK_THRESHOLD (40%) count.
    # Algorithm: accumulate raw weighted score per field (mark * weight),
    # then normalise so the top field = 100% and others scale proportionally.
    # This ensures weights actually determine ranking correctly.
    field_raw = {}

    for subj, mark in entered_marks.items():
        if mark >= MARK_THRESHOLD:
            for field, weight in SUBJECT_FIELD_MAP[subj].items():
                field_raw[field] = field_raw.get(field, 0) + mark * weight

    if field_raw:
        max_raw = max(field_raw.values())
        for field, raw in field_raw.items():
            marks_scores[field] = round((raw / max_raw) * 100)

