# ── HELPER: compute field rankings ───────────────────────────────────────────
def compute_field_rankings(mode, scores, question_categories, marks_scores):
    import math

    # --- INTEREST SCORING: normalised z-score approach ---
    # Step 1: raw percentage per field (score / max_possible)
    raw_pcts = {}
    for field, score in scores.items():
        fq = sum(1 for c in question_categories if c == field)
        mx = fq * 5 if fq > 0 else 1
        mn = fq * 1 if fq > 0 else 1   # min possible (score_map min=1)
        raw_pcts[field] = (score - mn) / (mx - mn) * 100 if mx > mn else 50.0

    # Step 2: compute person's mean and std across all fields (removes response bias)
    vals = list(raw_pcts.values())
    mean_v = sum(vals) / len(vals) if vals else 50
    variance = sum((v - mean_v) ** 2 for v in vals) / len(vals) if vals else 1
    std_v = math.sqrt(variance) if variance > 0 else 1

    # Step 3: z-score each field, then rescale to 0-100 around 50
    # Clamp z to [-3, 3] to prevent extreme outliers dominating
    z_scores = {}
    for field, pct in raw_pcts.items():
        z = (pct - mean_v) / std_v
        z = max(-3.0, min(3.0, z))
        z_scores[field] = z

    # Step 4: rescale z-scores to 0-100 (z=-3→10, z=0→50, z=+3→90)
    interest_pcts = {}
    for field, z in z_scores.items():
        normalised = round(50 + (z / 3.0) * 40)
        normalised = max(5, min(95, normalised))
        interest_pcts[field] = normalised

    # --- MARKS SCORING: apply mild curve so 90%+ mark doesn't dominate unfairly ---
    curved_marks = {}
    for field, pct in marks_scores.items():
        # Square-root curve: spreads the middle range, compresses extremes
        curved = round(math.sqrt(pct / 100) * 100) if pct > 0 else 0
        curved_marks[field] = curved

    all_fields = list(scores.keys())
    field_pcts = {}

    if mode == "interest":
        field_pcts = interest_pcts.copy()

    elif mode == "marks":
        for field in all_fields:
            field_pcts[field] = curved_marks.get(field, 0)

    else:
        # Adaptive weight: if fewer than 3 subjects entered, trust interest more
        n_marks_entered = sum(1 for v in marks_scores.values() if v > 0)
        if n_marks_entered >= 6:
            w_interest, w_marks = 0.60, 0.40   # full combined
        elif n_marks_entered >= 3:
            w_interest, w_marks = 0.70, 0.30   # lean interest
        else:
            w_interest, w_marks = 0.85, 0.15   # mostly interest

        for field in all_fields:
            i_pct = interest_pcts.get(field, 50)
            m_pct = curved_marks.get(field, 0)
            if m_pct == 0:
                # No marks for this field — use interest only
                field_pcts[field] = i_pct
            else:
                field_pcts[field] = round(i_pct * w_interest + m_pct * w_marks)

    sorted_scores = sorted(field_pcts.items(), key=lambda x: x[1], reverse=True)
    return sorted_scores, field_pcts, interest_pcts

